import { GoogleGenAI, Type } from "@google/genai";
import { StoryNode } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

// Generates the next part of the story
export const generateStorySegment = async (
  basePrompt: string, 
  previousContext: string, 
  userChoice: string | null
): Promise<StoryNode> => {
  try {
    let promptText = "";
    if (!previousContext) {
      // Start of the stream
      promptText = `Start a visual story based on this premise: "${basePrompt}". 
      Write the first scene. It should be immersive and cinematic.
      Also provide a prompt to generate a visual image for this scene.
      Provide 2 distinct choices for the user to decide what happens next.
      Return JSON only.`;
    } else {
      // Continuation
      promptText = `Continue this story: "${previousContext}". 
      The user chose to: "${userChoice}".
      Write the next scene (keep it concise, under 50 words).
      Provide a prompt to generate a visual image for this new scene.
      Provide 2 distinct choices for what happens next.
      Return JSON only.`;
    }

    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: promptText,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            narrative: { type: Type.STRING },
            visualPrompt: { type: Type.STRING },
            choices: { 
              type: Type.ARRAY, 
              items: { type: Type.STRING } 
            }
          }
        }
      }
    });

    return JSON.parse(response.text.trim()) as StoryNode;
  } catch (error) {
    console.error("Story Gen Error:", error);
    return {
      narrative: "The signal is lost... attempting to reconnect to the timeline.",
      visualPrompt: "Static noise screen, glitch art, dark void",
      choices: ["Retry Connection", "Abort"]
    };
  }
};

// Generates the visual frame for the stream
export const generateStreamVisual = async (visualPrompt: string): Promise<string | null> => {
  try {
    // We use the generateContent method but specifically looking for image generation
    // Using gemini-2.5-flash-image or a similar model capable of image generation if available.
    // Based on guidelines, we use gemini-2.5-flash-image for general generation.
    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash-image",
      contents: `Generate a high quality, cinematic, photorealistic 16:9 image for: ${visualPrompt}`,
      config: {
        // Nano banana models do not support responseMimeType or Schema
        imageConfig: {
            aspectRatio: "16:9",
        }
      }
    });

    // Extract image
    for (const part of response.candidates?.[0]?.content?.parts || []) {
      if (part.inlineData) {
        return `data:image/png;base64,${part.inlineData.data}`;
      }
    }
    return null;
  } catch (error) {
    console.error("Image Gen Error:", error);
    return null; // Frontend will show a placeholder or previous image
  }
};

