import React, { useEffect, useState, useRef } from 'react';
import { Vibe, StoryNode } from '../types';
import { generateStorySegment, generateStreamVisual } from '../services/gemini';
import { Play, SkipForward, Radio, Eye, Command, Share2, Maximize2 } from 'lucide-react';

interface StreamPlayerProps {
  vibe: Vibe; // We pass the Vibe as the seed
}

const StreamPlayer: React.FC<StreamPlayerProps> = ({ vibe }) => {
  const [currentNode, setCurrentNode] = useState<StoryNode | null>(null);
  const [currentImage, setCurrentImage] = useState<string | null>(null);
  const [history, setHistory] = useState<string>("");
  const [loading, setLoading] = useState(true);
  const [generatingVisual, setGeneratingVisual] = useState(false);
  const [autoPlay, setAutoPlay] = useState(false);

  // Use a ref to track if we've initialized to prevent double-firing in strict mode
  const initialized = useRef(false);

  // Initialize Stream
  useEffect(() => {
    if (initialized.current) return;
    initialized.current = true;
    startStream();
  }, [vibe]);

  const startStream = async () => {
    setLoading(true);
    const node = await generateStorySegment(vibe.prompt, "", null);
    setCurrentNode(node);
    setHistory(node.narrative);

    // Generate initial visual
    setGeneratingVisual(true);
    const image = await generateStreamVisual(node.visualPrompt);
    setCurrentImage(image || vibe.thumbnail); // Fallback to thumbnail
    setGeneratingVisual(false);

    setLoading(false);
  };

  const handleChoice = async (choice: string) => {
    setLoading(true);
    // Optimistic update: show loading state

    const newNode = await generateStorySegment(vibe.prompt, history, choice);
    setCurrentNode(newNode);
    setHistory(prev => prev + " " + newNode.narrative);

    setGeneratingVisual(true);
    // Keep old image while new one generates for smooth transition? 
    // Or blur old one? Let's keep old one and blur it.
    const newImage = await generateStreamVisual(newNode.visualPrompt);
    if (newImage) setCurrentImage(newImage);
    setGeneratingVisual(false);

    setLoading(false);
  };

