           {currentImage && (
             <img 
               src={currentImage} 
               alt="Stream Visual" 
               className={`w-full h-full object-cover transition-all duration-1000 ${generatingVisual ? 'scale-105 blur-md brightness-50' : 'scale-100 blur-0 brightness-100'}`}
             />
           )}
           {/* Scanlines Effect */}
           <div className="absolute inset-0 pointer-events-none opacity-20 bg-[url('https://media.giphy.com/media/v1.Y2lkPTc5MGI3NjExMzM0MzM0MzM0MzM0MzM0MzM0MzM0MzM0MzM0MzM0MzM0MzM0MyZlcD12MV9pbnRlcm5hbF9naWZzX2dpZklkJmN0PWc/oEI9uBYSzLpBK/giphy.gif')] bg-cover mix-blend-overlay"></div>
        </div>

        {/* Loading Overlay */}
        {(loading) && (
          <div className="absolute inset-0 flex flex-col items-center justify-center bg-black/60 backdrop-blur-sm z-20">
            <div className="w-16 h-16 border-4 border-fuchsia-500 border-t-transparent rounded-full animate-spin"></div>
            <p className="mt-4 text-fuchsia-400 font-mono text-sm animate-pulse">GENERATING REALITY...</p>
          </div>
        )}

        {/* Narrative & Interface Layer */}
        <div className="absolute inset-0 flex flex-col justify-between z-10 p-6 lg:p-12 bg-gradient-to-t from-black via-transparent to-black/40">

          {/* Header */}
          <div className="flex justify-between items-start">
             <div className="flex items-center gap-3">
                <div className="bg-red-600/90 text-white text-[10px] font-black px-3 py-1 rounded-full animate-pulse-slow flex items-center gap-2">
                   <div className="w-2 h-2 bg-white rounded-full animate-pulse"></div>
                   LIVE GENERATION
