import { GoogleGenAI, Type } from "@google/genai";
import { SynthesisResult } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const synthesizeElements = async (elementA: string, elementB: string): Promise<SynthesisResult> => {
  try {
    const prompt = `
      Act as a sci-fi alchemy engine.
      Combine these two elements: "${elementA}" and "${elementB}".

      Rules:
      1. Create a NEW item based on a logical or creative fusion of the two.
      2. The theme is "Futuristic / Cyberpunk / Sci-Fi".
      3. Determine rarity based on how cool/powerful the result is (Common, Rare, Epic, Legendary, Exotic).
      4. Provide a prompt to generate a visual image for this new item.

      Examples:
      - Plasma + Alloy = Laser Sword
      - Data + Bio-Mass = AI Virus
      - Laser Sword + AI Virus = Corrupted Saber (Epic)

      Return JSON.
    `;

    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            name: { type: Type.STRING },
            description: { type: Type.STRING },
            rarity: { type: Type.STRING, enum: ['common', 'rare', 'epic', 'legendary', 'exotic'] },
            visualPrompt: { type: Type.STRING }
          }
        }
      }
    });

    return JSON.parse(response.text.trim()) as SynthesisResult;
  } catch (error) {
    console.error("Synthesis Error:", error);
    return {
      name: "Glitch",
      description: "Synthesis failed. Unstable matter produced.",
      rarity: "common",
      visualPrompt: "TV static noise glitch"
    };
  }
};

export const generateElementImage = async (visualPrompt: string): Promise<string | null> => {
  try {
    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash-image",
      contents: `Generate a single icon/object focused, cinematic, highly detailed sci-fi concept art. Center the object. Dark background. 16:9 aspect ratio. Prompt: ${visualPrompt}`,
      config: {
        imageConfig: {
            aspectRatio: "16:9",
        }
      }
    });

    for (const part of response.candidates?.[0]?.content?.parts || []) {
      if (part.inlineData) {
        return `data:image/png;base64,${part.inlineData.data}`;
      }
    }
    return null;
  } catch (error) {
    console.error("Image Gen Error:", error);
    return null;
  }
};

