      </div>

      <div className="flex items-center gap-4 md:gap-12 z-10">
        {/* Slot 1 */}
        <div className={`
          w-32 h-32 md:w-48 md:h-48 rounded-2xl border-2 border-dashed flex items-center justify-center relative transition-all duration-500
          ${slot1 ? 'border-cyan-500 bg-cyan-900/10' : 'border-white/10 bg-white/5'}
        `}>
          {slot1 ? (
            <>
              <img src={slot1.image} className="w-full h-full object-cover rounded-xl opacity-80" />
              <button onClick={() => onClearSlot(1)} className="absolute -top-3 -right-3 p-1.5 bg-red-500 rounded-full hover:bg-red-600 transition-colors">
                <X size={14} className="text-white" />
              </button>
              <div className="absolute bottom-2 left-0 right-0 text-center text-xs font-bold text-cyan-200">{slot1.name}</div>
            </>
          ) : (
            <span className="text-white/20 font-mono text-sm">SELECT A</span>
          )}
        </div>

        {/* Core */}
        <div className="relative">
          <button
            onClick={onSynthesize}
            disabled={!canSynthesize}
            className={`
              w-20 h-20 rounded-full flex items-center justify-center transition-all duration-300 shadow-[0_0_30px_rgba(6,182,212,0.1)]
              ${canSynthesize 
                ? 'bg-cyan-500 hover:bg-cyan-400 hover:scale-110 shadow-[0_0_50px_rgba(6,182,212,0.4)] cursor-pointer' 
                : 'bg-white/5 cursor-not-allowed opacity-50'}
              ${isSynthesizing ? 'animate-pulse scale-95' : ''}
            `}
          >
            {isSynthesizing ? (
              <Zap size={32} className="text-white animate-bounce" />
            ) : (
              <Atom size={32} className={`text-white ${canSynthesize ? 'animate-spin-slow' : ''}`} />
            )}
          </button>
        </div>

        {/* Slot 2 */}
        <div className={`
          w-32 h-32 md:w-48 md:h-48 rounded-2xl border-2 border-dashed flex items-center justify-center relative transition-all duration-500
          ${slot2 ? 'border-cyan-500 bg-cyan-900/10' : 'border-white/10 bg-white/5'}
