import React, { useState, useRef } from 'react';
import Navbar from './components/Navbar';
import ElementCard from './components/ElementCard';
import Reactor from './components/Reactor';
import { Element, SynthesisResult } from './types';
import { INITIAL_ELEMENTS } from './constants';
import { synthesizeElements, generateElementImage } from './services/gemini';
import { History, Sparkles } from 'lucide-react';

const App: React.FC = () => {
  const [elements, setElements] = useState<Element[]>(INITIAL_ELEMENTS);
  const [slot1, setSlot1] = useState<Element | null>(null);
  const [slot2, setSlot2] = useState<Element | null>(null);
  const [isSynthesizing, setIsSynthesizing] = useState(false);
  const [latestDiscovery, setLatestDiscovery] = useState<Element | null>(null);

  const containerRef = useRef<HTMLDivElement>(null);

  const handleElementClick = (element: Element) => {
    if (isSynthesizing) return;

    // If exact same element is clicked and is in slot, remove it?
    // Let's stick to simple filling logic
    if (!slot1) {
      setSlot1(element);
    } else if (!slot2) {
      setSlot2(element);
    } else {
      // Both full, maybe replace slot 2?
      setSlot2(element);
    }
  };

  const handleClearSlot = (slot: 1 | 2) => {
    if (slot === 1) setSlot1(null);
    else setSlot2(null);
  };

  const handleSynthesize = async () => {
    if (!slot1 || !slot2) return;
    setIsSynthesizing(true);
    setLatestDiscovery(null);

    // Call Gemini for logic
    const result: SynthesisResult = await synthesizeElements(slot1.name, slot2.name);

    // Call Gemini for Image
    const image = await generateElementImage(result.visualPrompt);

    const newElement: Element = {
      id: crypto.randomUUID(),
      name: result.name,
      description: result.description,
      rarity: result.rarity,
      image: image || "https://placehold.co/600x400/000000/FFF?text=No+Image",
      discoveredAt: Date.now(),
      parents: [slot1.id, slot2.id],
      isNew: true
    };

    setElements(prev => [newElement, ...prev]);
    setLatestDiscovery(newElement);
    setSlot1(null);
    setSlot2(null);
    setIsSynthesizing(false);

    // Scroll to top of list
    if (containerRef.current) {
        containerRef.current.scrollTop = 0;
    }
  };

  return (
    <div className="min-h-screen pt-20 pb-12 px-4 md:px-8 max-w-[1600px] mx-auto flex flex-col h-screen">
      <Navbar elementCount={elements.length} />

      {/* Main Game Area */}
      <div className="flex-1 flex flex-col lg:flex-row gap-6 overflow-hidden">

        {/* Left: Synthesis Area (Top on mobile) */}
        <div className="lg:w-[45%] flex flex-col gap-6">
          <div className="flex-1 glass-panel rounded-3xl flex flex-col relative overflow-hidden">
            <div className="absolute top-4 left-4 text-xs font-bold text-white/30 tracking-[0.2em]">REACTOR CORE</div>

            <div className="flex-1 flex flex-col justify-center">
                <Reactor 
                    slot1={slot1} 
                    slot2={slot2} 
                    isSynthesizing={isSynthesizing} 
                    onSynthesize={handleSynthesize}
                    onClearSlot={handleClearSlot}
                />
            </div>

            {/* Latest Discovery Popup */}
            {latestDiscovery && !isSynthesizing && (
                <div className="bg-black/80 backdrop-blur border-t border-white/10 p-6 animate-in slide-in-from-bottom duration-500">
                    <div className="flex items-start gap-4">
                         <div className="w-24 h-24 rounded-lg overflow-hidden border border-white/20 shrink-0">
                            <img src={latestDiscovery.image} className="w-full h-full object-cover" />
                         </div>
                         <div>
                            <div className="flex items-center gap-2 mb-1">
                                <span className="text-green-400 font-bold text-xs uppercase tracking-widest">Synthesis Complete</span>
                                <span className={`text-[10px] px-2 rounded border uppercase font-bold text-white/80`}>{latestDiscovery.rarity}</span>
                            </div>
                            <h2 className="text-2xl font-bold text-white mb-1">{latestDiscovery.name}</h2>
