}

import { GoogleGenAI } from "@google/genai";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

// We use a generator to stream the response back to the UI
export async function* streamResponse(
  history: { role: string; content: string }[],
  currentMessage: string
) {
  try {
    // 1. Setup the Chat with Gemini 3 Pro
    const chat = ai.chats.create({
      model: 'gemini-3-pro-preview', // The Heavy Hitter
      config: {
        systemInstruction: `
          You are PROMETHEUS, a high-level software architect and creative engine.
          You communicate with brevity, precision, and technical depth.
          You prefer 'JetBrains Mono' aesthetics in your formatting.
          When asked to code, provide production-ready, clean implementations.
          Your interface is a dark-mode terminal. Act the part.
        `,
        // Enable Deep Thinking for complex tasks
        thinkingConfig: { 
          thinkingBudget: 2048 // Allocating token budget for reasoning
        }, 
        temperature: 0.7,
      },
      history: history.map(h => ({
        role: h.role,
        parts: [{ text: h.content }]
      }))
    });

    // 2. Send the message and stream chunks
    const result = await chat.sendMessageStream({
      message: currentMessage
    });

    for await (const chunk of result) {
      // Yield the text as it arrives
      if (chunk.text) {
        yield chunk.text;
      }
    }

  } catch (error) {
    console.error("Prometheus Core Error:", error);
    yield "\n\n[SYSTEM ERROR]: Connection to Neural Core severed.";
  }
}

