import React, { useState } from 'react';
import Navbar from './components/Navbar';
import Terminal from './components/Terminal';
import InputConsole from './components/InputConsole';
import { Message, SystemStatus } from './types';
import { streamResponse } from './services/gemini';

const App: React.FC = () => {
  const [messages, setMessages] = useState<Message[]>([]);
  const [status, setStatus] = useState<SystemStatus['status']>('idle');

  const handleSendMessage = async (text: string) => {
    const userMsg: Message = {
      id: Date.now().toString(),
      role: 'user',
      content: text,
      timestamp: Date.now()
    };

    setMessages(prev => [...prev, userMsg]);
    setStatus('thinking');

    // Create a placeholder for the AI response
    const aiMsgId = (Date.now() + 1).toString();

    // Convert current messages to history format for the API
    const history = messages.map(m => ({ role: m.role, content: m.content }));

    let fullContent = '';
    let firstChunkReceived = false;

    try {
      const stream = streamResponse(history, text);

      for await (const chunk of stream) {
        if (!firstChunkReceived) {
          setStatus('streaming');
          firstChunkReceived = true;
          // Initialize AI message
          setMessages(prev => [...prev, {
            id: aiMsgId,
            role: 'model',
            content: chunk,
            timestamp: Date.now()
          }]);
          fullContent += chunk;
        } else {
          // Append to existing AI message
          fullContent += chunk;
          setMessages(prev => prev.map(m => 
            m.id === aiMsgId ? { ...m, content: fullContent } : m
          ));
        }
      }
      setStatus('idle');
    } catch (e) {
      setStatus('error');
    }
  };

  return (
    <div className="flex flex-col h-screen bg-[#09090b]">
      <Navbar />
      <Terminal messages={messages} status={status} />
      <InputConsole onSendMessage={handleSendMessage} isLoading={status !== 'idle' && status !== 'error'} />
    </div>
  );
};

export default App;

