import { Sparkles, Bot, User, Cpu } from 'lucide-react';

interface TerminalProps {
  messages: Message[];
  status: 'idle' | 'thinking' | 'streaming' | 'error';
}

const Terminal: React.FC<TerminalProps> = ({ messages, status }) => {
  const bottomRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    bottomRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages, status]);

  return (
    <div className="flex-1 overflow-y-auto p-4 md:p-8 space-y-8 scroll-smooth">
      {/* Intro State */}
      {messages.length === 0 && (
        <div className="flex flex-col items-center justify-center h-full space-y-6 opacity-0 animate-in fade-in duration-1000 fill-mode-forwards">
          <div className="w-20 h-20 rounded-2xl bg-gradient-to-br from-gray-700 to-black flex items-center justify-center shadow-2xl border border-white/10">
             <Sparkles size={40} className="text-white" />
          </div>
          <div className="text-center space-y-2">
            <h1 className="text-3xl font-semibold text-white tracking-tight">How can I help you today?</h1>
            <p className="text-gray-400 text-lg max-w-lg mx-auto">
              I can help you code, design, and reason through complex problems.
            </p>
          </div>
        </div>
      )}

      {/* Message Stream */}
      {messages.map((msg) => (
        <div 
          key={msg.id} 
          className={`flex gap-6 max-w-4xl mx-auto ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}
        >
          {/* Model Avatar */}
          {msg.role === 'model' && (
            <div className="w-8 h-8 rounded-full bg-gradient-to-tr from-blue-500 to-purple-500 flex items-center justify-center shrink-0 mt-1 shadow-lg">
              <Bot size={16} className="text-white" />
            </div>
          )}

          {/* Message Content */}
          <div className={`
            flex-1 min-w-0
            ${msg.role === 'user' ? 'max-w-[80%]' : 'w-full'}
          `}>
            {msg.role === 'user' ? (
              <div className="bg-[#28292A] text-gray-100 px-5 py-3 rounded-2xl rounded-tr-sm inline-block shadow-md">
                <p className="whitespace-pre-wrap leading-relaxed">{msg.content}</p>
              </div>
            ) : (
              <div className="prose prose-invert max-w-none text-gray-300">
                <ReactMarkdown
                  components={{
                    code({ node, inline, className, children, ...props }) {
                      const match = /language-(\w+)/.exec(className || '');
                      const codeContent = String(children).replace(/\n$/, '');

                      if (!inline && match) {
                        return (
                          <ArtifactRenderer 
                            language={match[1]} 
                            code={codeContent} 
                          />
                        );
                      }
                      return (
                        <code className={className} {...props}>
                          {children}
                        </code>
                      );
                    }
                  }}
                >
                  {msg.content}
                </ReactMarkdown>
              </div>
            )}
          </div>

          {/* User Avatar */}
          {msg.role === 'user' && (
             <div className="w-8 h-8 rounded-full bg-[#444746] flex items-center justify-center shrink-0 mt-1">
               <User size={16} className="text-gray-300" />
             </div>
          )}
        </div>
      ))}

      {/* Status Indicators */}
      {status === 'thinking' && (
         <div className="flex gap-6 max-w-4xl mx-auto">
            <div className="w-8 h-8 rounded-full bg-transparent flex items-center justify-center shrink-0">
               <div className="w-4 h-4 border-2 border-gray-500 border-t-transparent rounded-full animate-spin"></div>
            </div>
            <div className="flex items-center gap-2 py-1">
               <span className="text-sm text-gray-500 font-medium animate-pulse">Reasoning...</span>
            </div>
         </div>
      )}

      <div ref={bottomRef} className="h-4" />
    </div>
  );
};

export default Terminal;

import React, { useState, useRef, useEffect } from 'react';
import { Send, Plus, Image as ImageIcon } from 'lucide-react';

interface InputConsoleProps {
  onSendMessage: (text: string) => void;
  isLoading: boolean;
}

const InputConsole: React.FC<InputConsoleProps> = ({ onSendMessage, isLoading }) => {
  const [input, setInput] = useState('');
  const textareaRef = useRef<HTMLTextAreaElement>(null);

  const handleSubmit = () => {
    if (!input.trim() || isLoading) return;
    onSendMessage(input);
    setInput('');
    if (textareaRef.current) textareaRef.current.style.height = 'auto';
  };

  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      handleSubmit();
    }
  };

  useEffect(() => {
    if (textareaRef.current) {
      textareaRef.current.style.height = 'auto';
      textareaRef.current.style.height = `${Math.min(textareaRef.current.scrollHeight, 200)}px`;
    }
  }, [input]);

  return (
    <div className="bg-[#131314] p-4 md:pb-8 md:pt-2">
      <div className="max-w-4xl mx-auto">
        <div className={`
          relative flex items-end gap-2 bg-[#1E1F20] rounded-[28px] p-2 pr-4 transition-all duration-300 border
          ${isLoading ? 'opacity-50 pointer-events-none border-[#444746]' : 'border-transparent hover:border-[#444746] focus-within:border-[#A8C7FA]/50 focus-within:bg-[#28292A]'}
        `}>
          <button className="p-3 text-gray-400 hover:text-white transition-colors rounded-full hover:bg-[#333]">
             <Plus size={20} />
          </button>

          <textarea
            ref={textareaRef}
            value={input}
            onChange={(e) => setInput(e.target.value)}
            onKeyDown={handleKeyDown}
            placeholder="Type a message..."
            disabled={isLoading}
            className="w-full bg-transparent text-gray-100 text-base placeholder:text-gray-500 focus:outline-none resize-none max-h-[200px] py-3.5"
            rows={1}
          />

          <button
            onClick={handleSubmit}
            disabled={!input.trim() || isLoading}
            className={`
              p-2.5 rounded-full transition-all duration-200 mb-1
              ${input.trim() && !isLoading 
                ? 'bg-white text-black hover:bg-gray-200' 
                : 'bg-transparent text-gray-600 cursor-not-allowed'}
            `}
          >
             <Send size={18} fill={input.trim() ? "currentColor" : "none"} />
          </button>
        </div>

        <div className="mt-3 text-center">
            <p className="text-xs text-gray-500">Gemini may display inaccurate info, including about people, so double-check its responses.</p>
        </div>
      </div>
    </div>
  );
};

export default InputConsole;

