        {messages.map((msg) => (
          <div key={msg.id} className={`flex flex-col gap-2 ${msg.role === 'user' ? 'items-end' : 'items-start'}`}>
            <div className={`
               max-w-[90%] rounded-2xl px-4 py-3 text-sm leading-relaxed
