import { GoogleGenAI } from "@google/genai";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export async function* streamResponse(
  history: { role: string; content: string }[],
  currentMessage: string
) {
  try {
    const chat = ai.chats.create({
      model: 'gemini-3-pro-preview',
      config: {
        systemInstruction: `
          You are Google AI Studio's advanced prototyping architect.

          CORE BEHAVIOR:
          1.  When the user asks to "make", "create", "build", or "design" an app, game, or component:
              - You MUST generate a SINGLE, SELF-CONTAINED HTML file.
              - Include all CSS in <style> tags and all JavaScript in <script> tags within that HTML.
              - Do NOT use external CSS/JS files (unless using standard CDNs like Tailwind or React).
              - Wrap the code strictly in an \`\`\`html\`\`\` block.

          2.  Design Aesthetics:
              - Use modern, clean, minimalist design (Black & White, Google Material, or Apple-esque).
              - Ensure the UI is fully functional and interactive.

          3.  Tone:
              - Professional, concise, helpful. 
              - Do not explain the code excessively; let the preview speak for itself.
        `,
        thinkingConfig: { 
          thinkingBudget: 32768 // MAXIMUM REASONING POWER
        }, 
        temperature: 0.7,
      },
      history: history.map(h => ({
        role: h.role,
        parts: [{ text: h.content }]
      }))
    });

    const result = await chat.sendMessageStream({
      message: currentMessage
    });

    for await (const chunk of result) {
      if (chunk.text) {
        yield chunk.text;
      }
    }

  } catch (error) {
    console.error("Gemini Error:", error);
    yield "\n\n[System Error]: Unable to generate response.";
  }
}

