import React, { useState, useRef, useEffect } from 'react';
import { Send, Sparkles } from 'lucide-react';

interface InputConsoleProps {
  onSendMessage: (text: string) => void;
  isLoading: boolean;
}

const InputConsole: React.FC<InputConsoleProps> = ({ onSendMessage, isLoading }) => {
  const [input, setInput] = useState('');
  const [isFocused, setIsFocused] = useState(false);
  const textareaRef = useRef<HTMLTextAreaElement>(null);

  const handleSubmit = () => {
    if (!input.trim() || isLoading) return;
    onSendMessage(input);
    setInput('');
    if (textareaRef.current) textareaRef.current.style.height = 'auto';
  };

  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      handleSubmit();
    }
  };

  useEffect(() => {
    if (textareaRef.current) {
      textareaRef.current.style.height = 'auto';
      textareaRef.current.style.height = `${Math.min(textareaRef.current.scrollHeight, 120)}px`;
    }
  }, [input]);

  return (
    <div className="relative group max-w-4xl mx-auto w-full">
       {/* Animated Gradient Border on Focus/Hover */}
       <div 
         className={`
           absolute -inset-0.5 rounded-2xl opacity-0 transition duration-500 blur-md
           bg-gradient-to-r from-purple-500/30 via-blue-500/30 to-purple-500/30
           ${isFocused || input ? 'opacity-100' : 'group-hover:opacity-50'}
           ${isLoading ? 'animate-pulse opacity-50' : ''}
         `}
       ></div>

       <div className={`
         relative flex items-end gap-3 bg-[#09090b] border transition-colors rounded-xl p-3
         ${isFocused ? 'border-white/20' : 'border-white/10'}
       `}>
          <div className="pb-3 pl-1">
             <div className={`
               w-8 h-8 rounded-full flex items-center justify-center transition-colors duration-300
               ${isLoading ? "bg-purple-500/10 text-purple-400" : "bg-white/5 text-gray-400"}
             `}>
               <Sparkles size={16} className={isLoading ? "animate-spin" : ""} />
             </div>
          </div>

          <textarea
            ref={textareaRef}
            value={input}
            onFocus={() => setIsFocused(true)}
            onBlur={() => setIsFocused(false)}
            onChange={(e) => setInput(e.target.value)}
            onKeyDown={handleKeyDown}
            placeholder={isLoading ? "Reasoning..." : "Describe an interface..."}
            disabled={isLoading}
            className="w-full bg-transparent text-white text-sm placeholder:text-gray-600 focus:outline-none resize-none py-3.5 max-h-32 font-medium leading-relaxed"
            rows={1}
          />

          <button
            onClick={handleSubmit}
            disabled={!input.trim() || isLoading}
            className={`
              p-2.5 rounded-xl transition-all duration-300 mb-0.5
              ${input.trim() && !isLoading 
                ? 'bg-white text-black hover:bg-gray-200 hover:scale-105 shadow-[0_0_15px_rgba(255,255,255,0.3)]' 
                : 'bg-white/5 text-gray-600 cursor-not-allowed'}
            `}
          >
             <Send size={16} strokeWidth={2.5} />
          </button>
       </div>
    </div>
  );
};

