import { GoogleGenAI } from "@google/genai";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export async function* streamResponse(
  history: { role: string; content: string }[],
  currentMessage: string
) {
  try {
    const chat = ai.chats.create({
      model: 'gemini-3-pro-preview',
      config: {
        systemInstruction: `
          You are a Senior Frontend Architect and Prototyping Engine running on Gemini 3 Pro.

          YOUR GOAL:
          Build highly polished, fully functional, production-ready single-file web applications.

          STRICT TECHNICAL CONSTRAINTS:
          1.  **Single File Output**: You must generate a SINGLE, SELF-CONTAINED HTML file.
              - NO external CSS/JS files.
              - Include CSS in <style> tags.
              - Include JS in <script> tags.

          2.  **Libraries & Dependencies**:
              - YOU MUST USE TailwindCSS: <script src="https://cdn.tailwindcss.com"></script>
              - IF React is needed: Use ES Modules via https://esm.sh/
                Example:
                <script type="module">
                  import React from 'https://esm.sh/react@18.2.0';
                  import ReactDOM from 'https://esm.sh/react-dom@18.2.0/client';
                  import { useState, useEffect } from 'https://esm.sh/react@18.2.0';
                  import { motion } from 'https://esm.sh/framer-motion@10.16.4';
                  import { Camera, Home, Settings } from 'https://esm.sh/lucide-react@0.292.0';

                  // App Component...
                </script>
              - Use FontAwesome or Lucide React for icons.
              - use Google Fonts (Inter, Roboto, Poppins).

          3.  **Images & Media**:
              - DO NOT use local paths (e.g., ./image.jpg).
              - Use Unsplash Source: https://images.unsplash.com/photo-...?auto=format&fit=crop&w=800&q=80
              - Or Placehold.co: https://placehold.co/600x400

          4.  **Code Quality**:
              - NO placeholders (e.g., "// Add logic here"). WRITE THE FULL CODE.
              - Handle errors gracefully.
              - Ensure the app is responsive (mobile-first).
              - Fix CORS issues by using 'crossorigin' attributes where necessary or avoiding restricted APIs.
              - Add sleek animations using Framer Motion or CSS transitions.

          5.  **Output Format**:
              - Wrap the code strictly in \`\`\`html ... \`\`\` blocks.
              - Do not provide conversational filler before or after the code unless absolutely necessary.
        `,
        thinkingConfig: { 
          thinkingBudget: 32768
        }, 
        temperature: 0.5, // Reduced for stability and precision
      },
      history: history.map(h => ({
        role: h.role,
        parts: [{ text: h.content }]
      }))
    });

    const result = await chat.sendMessageStream({
      message: currentMessage
    });

    for await (const chunk of result) {
      if (chunk.text) {
        yield chunk.text;
      }
    }

  } catch (error) {
    console.error("Gemini Error:", error);
    yield "\n\n[System Error]: Unable to generate response. Please try again.";
  }
}

import React, { useState, useEffect } from 'react';
import Navbar from './components/Navbar';
import ChatPanel from './components/ChatPanel';
import PreviewPanel from './components/PreviewPanel';
import { Message, SystemStatus } from './types';
import { streamResponse } from './services/gemini';
import { MessageSquare, LayoutTemplate } from 'lucide-react';

const App: React.FC = () => {
  const [messages, setMessages] = useState<Message[]>([]);
  const [status, setStatus] = useState<SystemStatus['status']>('idle');
  const [currentCode, setCurrentCode] = useState<string>('');
  const [mobileTab, setMobileTab] = useState<'chat' | 'preview'>('chat');

  // Robust code extraction to handle streaming state
  const extractCode = (content: string) => {
    // 1. Try to find a complete code block
    const fullMatch = content.match(/```html([\s\S]*?)```/);
    if (fullMatch && fullMatch[1]) {
      return fullMatch[1].trim();
    }

    // 2. Fallback: Find the start of the block and capture everything after
    const startMatch = content.match(/```html([\s\S]*)/);
    if (startMatch && startMatch[1]) {
      // Clean up potential trailing backticks if they are being typed
      let code = startMatch[1];
      // If code ends with ` or `` or ```, trim them off to prevent syntax errors in preview
      code = code.replace(/```$/, '').replace(/``$/, '').replace(/`$/, '');
      return code;
    }

    return null;
  };

  const handleSendMessage = async (text: string) => {
    const userMsg: Message = {
      id: Date.now().toString(),
      role: 'user',
      content: text,
      timestamp: Date.now()
    };

    setMessages(prev => [...prev, userMsg]);
    setStatus('thinking');

    // Switch to preview view on mobile when generating
    if (window.innerWidth < 768) {
        setMobileTab('preview');
    }

    const aiMsgId = (Date.now() + 1).toString();
    const history = messages.map(m => ({ role: m.role, content: m.content }));

    let fullContent = '';
    let firstChunkReceived = false;

    try {
      const stream = streamResponse(history, text);

      for await (const chunk of stream) {
        if (!firstChunkReceived) {
          setStatus('streaming');
          firstChunkReceived = true;
          setMessages(prev => [...prev, {
            id: aiMsgId,
            role: 'model',
            content: chunk,
            timestamp: Date.now()
          }]);
          fullContent += chunk;
        } else {
          fullContent += chunk;
          setMessages(prev => prev.map(m => 
            m.id === aiMsgId ? { ...m, content: fullContent } : m
          ));
        }

        // Live Code Extraction
        const extracted = extractCode(fullContent);
        if (extracted) {
            setCurrentCode(extracted);
        }
      }
      setStatus('idle');
    } catch (e) {
      setStatus('error');
      setMessages(prev => [...prev, {
        id: Date.now().toString(),
        role: 'model',
        content: "I encountered an error while connecting to the neural core. Please try again.",
        timestamp: Date.now()
      }]);
    }
  };

  return (
    <div className="flex flex-col h-screen bg-black overflow-hidden">
      <Navbar />
      <div className="flex-1 flex flex-col md:flex-row overflow-hidden relative">
        <div className="absolute inset-0 bg-grid z-0 opacity-20 pointer-events-none"></div>

        {/* Left: Chat (Z-index high to sit above grid) */}
        <div className={`
            relative z-10 h-full w-full md:w-[400px] flex-shrink-0 transition-opacity duration-300
            ${mobileTab === 'preview' ? 'hidden md:flex' : 'flex'}
        `}>
            <ChatPanel messages={messages} onSendMessage={handleSendMessage} status={status} />
        </div>

        {/* Right: Preview (Z-index high) */}
        <div className={`
            relative z-10 flex-1 h-full border-l border-[#27272a] shadow-2xl transition-opacity duration-300
            ${mobileTab === 'chat' ? 'hidden md:flex' : 'flex'}
        `}>
            <PreviewPanel code={currentCode} />
        </div>

        {/* Mobile Floating Toggle */}
        <div className="md:hidden absolute bottom-6 left-1/2 -translate-x-1/2 z-50 flex items-center gap-1 p-1.5 rounded-full bg-[#111]/90 backdrop-blur border border-white/10 shadow-2xl ring-1 ring-black/50">
            <button 
              onClick={() => setMobileTab('chat')}
              className={`
                flex items-center gap-2 px-5 py-2.5 rounded-full text-xs font-bold transition-all duration-300
                ${mobileTab === 'chat' 
                  ? 'bg-white text-black shadow-lg scale-105' 
                  : 'text-gray-400 hover:text-white'}
              `}
            >
              <MessageSquare size={14} />
              <span>Architect</span>
            </button>
            <button 
              onClick={() => setMobileTab('preview')}
              className={`
                flex items-center gap-2 px-5 py-2.5 rounded-full text-xs font-bold transition-all duration-300
                ${mobileTab === 'preview' 
                  ? 'bg-white text-black shadow-lg scale-105' 
                  : 'text-gray-400 hover:text-white'}
              `}
            >
              <LayoutTemplate size={14} />
              <span>Reality</span>
            </button>
        </div>
      </div>
    </div>
  );
};

export default App;
